2190		function cl_fix_in_range(	a			: std_logic_vector; 
2191									a_fmt		: FixFormat_t; 
2192									result_fmt	: FixFormat_t; 
2193									round		: FixRound_t	:= Trunc_s) 
2194									return boolean is
2195			-- Note: This matches the python implementation
2196			constant rndFmt_c : FixFormat_t := 
2197				(
2198					Signed		=> a_fmt.Signed,
2199					IntBits		=> a_fmt.IntBits + 1,
2200					FracBits	=> result_fmt.FracBits
