--! cl_fix_from_bits_as_int implementation	
function cl_fix_from_bits_as_int(	a 		: integer;
									aFmt 	: FixFormat_t)
									return std_logic_vector is
begin
	if aFmt.Signed then
		return std_logic_vector(to_signed(a, cl_fix_width(aFmt)));
